#include <iostream>
#include <string>

using namespace std;

int main() {
    string num;
    char digit;
    cin >> num >> digit;

    int count = 0;
    for (char ch : num) {
        if (ch == digit) {
            count++;
        }
    }

    cout << count << endl;
    return 0;
}
